import { cx } from '@/utils/cx';
import { SectionHeading } from '../../molecules/SectionHeading';
import { WithDataId } from '@/types/withDataId';

export type SectionProps = {
  title: string;
  subtitle?: React.ReactNode;
  buttons?: React.ReactNode;
  children: React.ReactNode;
  className?: string;
  responsive?: boolean;
} & WithDataId;

export function Section({
  title,
  subtitle,
  buttons,
  children,
  className,
  responsive = true,
  'data-id': dataId,
}: SectionProps) {
  return (
    <div
      className={cx(
        'p-6 mt-4 space-y-6 w-full rounded-xl border border-secondary',
        className,
      )}
    >
      <SectionHeading.Root data-id={`${dataId}`}>
        <SectionHeading.Group>
          <SectionHeading.Header
            title={title}
            subtitle={subtitle}
          />
          {buttons && (
            <SectionHeading.Actions data-id={`${dataId}-actions`}>
              {buttons}
            </SectionHeading.Actions>
          )}
        </SectionHeading.Group>
      </SectionHeading.Root>
      <div
        className={cx(
          'flex gap-6',
          responsive ? 'flex-row lg:flex-col' : 'flex-col',
        )}
      >
        {children}
      </div>
    </div>
  );
}
